const page2 = {{ allSpoolsQuery2.data || [] }};

const data = [...page1, ...page2];
const selectedStatus = {{ statusTabs.value }};

// --- Helpers ---
function parseDate(d) {
  if (!d) return null;

  // Convert YYYY-MM-DD to full timestamp
  if (/^\d{4}-\d{2}-\d{2}$/.test(d)) {
    d = `${d}T00:00:00`;
  }

  const dt = new Date(d);
  return isNaN(dt) ? null : dt;
}

function formatDate(dateStr) {
  const dt = parseDate(dateStr);
  if (!dt) return null;

  const mm = String(dt.getMonth() + 1).padStart(2, "0");
  const dd = String(dt.getDate()).padStart(2, "0");
  const yyyy = dt.getFullYear();
  return `${mm}-${dd}-${yyyy}`;
}

// --- Filter by selected tab ---
const filteredData = selectedStatus
  ? data.filter(r => {
      const raw = (r.current_status || "").toLowerCase().trim();
      const normalized = raw.replace(/^\d+\s*-\s*/, "").trim();
      const tab = selectedStatus.toLowerCase().trim();

      return (
        raw === tab ||
        normalized === tab ||
        raw.includes(tab) ||
        normalized.includes(tab)
      );
    })
  : data;

// --- Compute Stats ---
const today = new Date();
today.setHours(0, 0, 0, 0);

const totalPackages = filteredData.length;
const totalWeldInches = filteredData.reduce(
  (sum, r) => sum + (r.total_weld_inches || 0),
  0
);
const totalFabHours = filteredData.reduce(
  (sum, r) => sum + (r.estimated_fab_hours || 0),
  0
);

// Count past due
const pastDueCount = filteredData.filter(r => {
  const date = parseDate(r.date_needed);
  return date && date < today;
}).length;

// --- NEXT FUTURE PACKAGE ---
const futureList = filteredData
  .map(r => ({
    ...r,
    _parsed: parseDate(r.date_needed),
    _origin: r.date_needed
  }))
  .filter(r => r._parsed && r._parsed >= today)
  .sort((a, b) => a._parsed - b._parsed);

const nextDue = futureList.length > 0 ? futureList[0] : null;

// --- MOST RECENT PAST DUE PACKAGE ---
const pastList = filteredData
  .map(r => ({
    ...r,
    _parsed: parseDate(r.date_needed),
    _origin: r.date_needed
  }))
  .filter(r => r._parsed && r._parsed < today)
  .sort((a, b) => b._parsed - a._parsed);

const lastPastDue = pastList.length > 0 ? pastList[0] : null;

// --- Return Object ---
return {
  totalPackages,
  totalWeldInches,
  totalFabHours,
  pastDue: pastDueCount,
  nextDue: nextDue
    ? {
        ...nextDue,
        formatted_date_needed: formatDate(nextDue._origin),
      }
    : null,
  lastPastDue: lastPastDue
    ? {
        ...lastPastDue,
        formatted_date_needed: formatDate(lastPastDue._origin),
      }
    : null
};
