// --------------------
// Pagination config
// --------------------
const BASE_URL =
  "https://pzmjeppeaiztqzmgkgmp.supabase.co/rest/v1/spools_dashboard";

const PAGE_SIZE = 1000;
let page = 0;
let allRows = [];

// --------------------
// Fetch loop
// --------------------
while (true) {
  let params = [
    "select=*",
    "order=spool_name.asc",
    `limit=${PAGE_SIZE}`,
    `offset=${page * PAGE_SIZE}`
  ];

  if (effectivePackageFilter) {
    params.push(`package_id=eq.${encodeURIComponent(effectivePackageFilter)}`);
  }

  if (projectId) {
    params.push(`project_id=eq.${encodeURIComponent(projectId)}`);
  }

  if (materialType) {
    params.push(`material_type=eq.${encodeURIComponent(materialType)}`);
  }

  if (status) {
    params.push(`current_status=eq.${encodeURIComponent(status)}`);
  }

  const queryUrl = `${BASE_URL}?${params.join("&")}`;

  const res = await fetch(queryUrl, {
    method: "GET",
    headers: {
      apikey: retoolContext.configVars.supabaseApiKey_fab_prod,
      Authorization: `Bearer ${access_token}`,
      "Content-Type": "application/json",
    },
  });

  const rows = await res.json();

  if (!Array.isArray(rows) || rows.length === 0) break;

  allRows = allRows.concat(rows);

  if (rows.length < PAGE_SIZE) break;

  page++;
}

console.log("Total rows fetched:", allRows.length);

return allRows;




