  if (isWeldedOut(status)) {
    overallWeldedOutSpools += 1;
  }

  // ---- PROJECT ----
  projectTotals[project] = (projectTotals[project] || 0) + 1;

  if (isWeldedOut(status)) {
    projectWeldedOut[project] =
